INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"问什么处所：你住在哪里？、这话你是从哪里听来的？");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"泛指任何处所：农村和城市，无论哪里，都是一片欣欣向荣的新气象、她走到哪里，就把好事做到哪里。");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"用于反问句，表示意在否定：这样美好的生活，哪里是解放前能想到的？（＝不是…）、哪里知道刚走出七八里地，天就下起雨来了？（＝不料…）");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"谦辞，用来婉转地推辞对自己的褒奖：‘你这篇文章写得真好！’‘哪里，哪里！’");
