INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id," 长江 和 黄河 。");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"指大河流。");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"犹江山，山河。");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"犹江湖。泛指四方各地。");
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id,"《墨子·亲士》：“ 江  河 之水，非一源之水也；千鎰之裘，非一狐之白也。” 晋  葛洪 《抱朴子·钧世》：“以此易见，比彼难晓，犹沟澮之方 江  河 ，螘垤之并 嵩  岱 也。”","");;
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id,"《六韬·守土》：“涓涓不塞，将为江河。”《宋史·食货志下二》：“州县督捕加峻，私小黄钱投委江河，不敢復出。”《警世通言·旌阳宫铁树镇妖》：“老翁有缘，幸遇小生相救。不然，今日是个屋舍，后日是个江河，君家且葬鱼腹矣。” 凌力 《星星草》第四章四：“ 遵王 抬头望去，大队像滚滚江河似地奔腾向前。”","");;
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id,"《晋书·王导传》：“ 周顗 中坐而叹曰：‘风景不殊，举目有江河之异。’皆相视流涕。”按，江河，《世说新语·言语》作“山河”。","");;
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id,"《敦煌曲子词·菩萨蛮》：“权隐在江河，龙门终一过。” 清  王韬 《瓮牑馀谈·外国牙科》：“其所称牙有虫者，以药敷之，顷刻可出，此皆係江河鬻术者为之，非果具有真实本领也。”","");;
INSERT INTO same_diff_word (word, same_word, diff_word) VALUES ("江河","","");
