INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"成长为大人。");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"指年龄增大。");
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id,"《国语·晋语九》：“ 瑶 之贤於人者五，其不逮者一也。美鬢长大则贤。”《史记·淮阴侯列传》：“ 淮阴 屠中少年有侮 信 者，曰：‘若虽长大，好带刀剑，中情怯耳。’” 宋  苏舜钦 《答宋太祝见赠》诗：“丈夫气刚精，不必在长大。” 沙汀 《替身》：“保长有三十岁，又长大，又结实。”","");;
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id,"《礼记·月令》：“﹝孟夏之月﹞命太尉，赞桀俊，遂贤良，举长大。” 孔颖达 疏：“经云举长大者，谓用长大之人。故 王肃 云：‘举形貌壮大者。’”","");;
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id,"《释名·释姿容》：“匍匐，小儿时也……人虽长大，及其求事尽力之勤犹亦称之。”《百喻经·医与王女药令卒长大喻》：“﹝王﹞不晓筹量生来年月，见其长大，谓是药力。”《二十年目睹之怪现状》第三回：“家伯是在 北京 长大的，在 北京 成的家。”","");;
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id," 三国  魏  曹丕 《与吴质书》：“年行已长大，所怀万端。” 明  唐顺之 《书丁近斋示孙卷后》：“年既长大，则已知记诵佔毕词章之习，非所以反身而崇德。”","");;
