INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id," 南朝  梁  陶弘景 《授陆敬游十赉文》：“賚尔大砚一面，纸笔副之，可以临文写字，对真受言。” 唐  高骈 《寄鄠杜李遂良处士》诗：“池边写字师前辈，座右题铭律后生。” 宋  文同 《可笑口号》之三：“可笑此公何太惑，读书写字到三更。” 赵树理 《金字》：“一天，镇长交给我一卷缎子和一包泥金，要我替他写字。”","");;
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id," 明  王琼 《双溪杂记》：“以此有不待缺而陞者，如……医士出身陞至太医院使，写字出身，在内阁书办，陞至编脩。”","");;
INSERT INTO same_diff_word (word, same_word, diff_word) VALUES ("写字","","");
