INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"古地名。在今 江西省  南昌市 北。");
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id," 唐  寒山 《诗》之一九三：“飢餐一粒伽陀药，心地调和倚石头。” 宋  杨万里 《题望韶亭》诗：“ 嶧山 桐树半夜鸣， 泗水 石头清昼跃。”《儒林外史》第二五回：“却是一条平坦大路，一块石头也没有。” 郭小川 《闪耀吧，青春的火光》诗：“在青春的世界里，沙粒要变成真珠，石头要化做黄金。”","");;
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id," 北魏  郦道元 《水经注·赣水》：“水之西岸有盘石，谓之 石头 ， 津步 之处也。”《晋书·殷浩传》：“父 羡 ，字 洪乔 ，为 豫章 太守，都下人士因其致书者百餘函。行次 石头 ，皆投之水中，曰：‘沉者自沉，浮者自浮， 殷洪乔 不为致书邮。’” 明  张煌言 《＜奇零草＞序》：“凡留供覆瓿者，尽同 石头 书邮，始知文字亦有阳九之厄也。” 清  恽敬 《杂记》：“《世説》言 石头 …… 豫章 之 石头 ，见《晋书》 周访 及 侯安都 传。”","");;
INSERT INTO same_diff_word (word, same_word, diff_word) VALUES ("石头","","");
