INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"唐 代 河中府 的名胜。原在 山西  蒲州府 西南(今 永济县 )，前瞻 中条山 ，下瞰 大河 。因常有鹳雀栖息，故名。后为 河 水冲没。");
INSERT INTO hz_word_sample (hz_word_id, cn, en) VALUES (@id," 唐  李益 《同崔颁登鹳雀楼》诗：“ 鸛雀楼 西百尺檣，汀洲云树共茫茫。” 宋  沉括 《梦溪笔谈·艺文二》：“ 河中府  鸛雀楼 ，三层，前瞻 中条 ，下瞰 大河 。” 清  王士禛 《河中感怀寄诸兄》诗：“京华故国俱千里，心折西风 鸛雀楼 。”","");;
