INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"中国第二大河。源于青海巴颜喀拉山北麓约古宗列盆地，流经青海、四川、甘肃、宁夏、内蒙古、陕西、山西、河南、山东七省区，注入渤海。长5464千米，流域面积75万多平方千米。天然径流量570多亿立方米。年均含沙量3");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"7千克/立方米(陕县站)，年均输沙量16亿吨，均居世界大河之首。90%的泥沙来自中游黄土高原。下游泥沙淤积，成为“悬河”(即“地上河”)，历史上经常决口泛滥，并发生重要改道二十六次。1955年起进行大规模综合治理和开发，在上中游除进行水土保持工作外，还兴建了三门峡、青铜峡、");
