INSERT INTO hz_word_dict (pinying, word, en_word, en_audio_url, audio) VALUES ("huáng shān","黄山","Mount Huangshan","http://cdnmu.gurobot.cn/saodubi/dict/hanzi_fanyi_audio/M/Mount Huangshan.mp3","http://cdn.ococci.com/dict_ali/2022-01-29/1643436911465356234_7b0076de-92eb-c9c2-6fcb-1a1d4b2f76c1.mp3");
INSERT INTO hz_word_explanation (hz_word_id, explanation) VALUES (@id,"古称“黟山”。在安徽省南部黄山市境。主峰光明顶(1841米)，最高峰莲花峰(1873米)。有二湖、三瀑、二十四溪、七十二名峰，风景绝佳，以奇松、怪石、云海、温泉著名，并称“黄山四绝”。明代著名地理学家徐霞客有“五岳归来不看山，黄山归来不看岳”之说。有天都峰、莲花峰、始信峰、百丈瀑、玉屏楼、半山寺、黄山温泉等名胜古迹。为全国重点风景名胜区，并被列入世界遗产名录。");
INSERT INTO same_diff_word (word, same_word, diff_word) VALUES ("黄山","","");
